import mysql from "mysql2/promise"; import bcrypt from "bcryptjs"; import env from "./env.js"; // Create pool connection const createPool = async () => { return mysql.createPool({ host: env.DB_HOST, port: env.DB_PORT, user: env.DB_USER, password: env.DB_PASSWORD, database: env.DB_NAME, waitForConnections: true, connectionLimit: 10, queueLimit: 0, enableKeepAlive: true, keepAliveInitialDelay: 0, }); }; let pool = null; // ============================================ // DATABASE INITIALIZATION - COMPLETE SETUP // ============================================ export const initializeDatabase = async () => { try { console.log("📦 Initializing SWOMS Database System..."); // First, create connection without database to create it const adminConnection = await mysql.createConnection({ host: env.DB_HOST, port: env.DB_PORT, user: env.DB_USER, password: env.DB_PASSWORD, }); // Create database if not exists await adminConnection.query(`CREATE DATABASE IF NOT EXISTS ${env.DB_NAME}`); console.log(`✅ Database '${env.DB_NAME}' ready`); // Switch to our database await adminConnection.query(`USE ${env.DB_NAME}`); // Create all tables in correct order await createAllTables(adminConnection); // Close admin connection await adminConnection.end(); // Now create the connection pool pool = await createPool(); // Insert minimal required data // await insertMinimalRequiredData(); console.log("🎉 Database initialization completed successfully!"); console.log(`📊 Database: ${env.DB_NAME}@${env.DB_HOST}:${env.DB_PORT}`); return true; } catch (error) { console.error("❌ Database initialization failed:", error.message); throw error; } }; // ============================================ // TABLE CREATION - ALL TABLES IN CORRECT ORDER // ============================================ const createAllTables = async (connection) => { console.log("🔧 Creating all database tables in correct order..."); // 1. USERS table (created first - no foreign keys) const usersTable = ` CREATE TABLE IF NOT EXISTS users ( user_id INT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(100) UNIQUE NOT NULL, email VARCHAR(150) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role ENUM( 'admin', 'instructor', 'department_head', 'dean', 'cde_director', 'hr_director', 'vpaa', 'vpaf', 'finance', 'registrar' ) NOT NULL DEFAULT 'instructor', is_active BOOLEAN DEFAULT TRUE, last_login DATETIME, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, created_by INT, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 2. COLLEGES table (depends on users) const collegesTable = ` CREATE TABLE IF NOT EXISTS colleges ( college_id INT PRIMARY KEY AUTO_INCREMENT, college_code VARCHAR(20) UNIQUE NOT NULL, college_name VARCHAR(150) NOT NULL, dean_user_id INT, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (dean_user_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 3. DEPARTMENTS table (depends on colleges and users) const departmentsTable = ` CREATE TABLE IF NOT EXISTS departments ( department_id INT PRIMARY KEY AUTO_INCREMENT, department_code VARCHAR(20) UNIQUE NOT NULL, department_name VARCHAR(150) NOT NULL, college_id INT NOT NULL, head_user_id INT, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (college_id) REFERENCES colleges(college_id) ON DELETE CASCADE, FOREIGN KEY (head_user_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 4. STAFF PROFILES table (depends on users and departments) const staffProfilesTable = ` CREATE TABLE IF NOT EXISTS staff_profiles ( staff_id INT PRIMARY KEY AUTO_INCREMENT, user_id INT UNIQUE NOT NULL, employee_id VARCHAR(50) UNIQUE NOT NULL, first_name VARCHAR(100) NOT NULL, last_name VARCHAR(100) NOT NULL, middle_name VARCHAR(100), department_id INT NOT NULL, academic_rank ENUM( 'graduate_assistant', 'assistant_lecturer', 'lecturer', 'assistant_professor', 'associate_professor', 'professor' ) NOT NULL DEFAULT 'lecturer', employment_type ENUM('full_time', 'part_time', 'contract') DEFAULT 'full_time', hire_date DATE, phone VARCHAR(20), address TEXT, date_of_birth DATE, gender ENUM('male', 'female', 'other'), created_by INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 5. ACADEMIC YEARS table (independent) const academicYearsTable = ` CREATE TABLE IF NOT EXISTS academic_years ( academic_year_id INT PRIMARY KEY AUTO_INCREMENT, year_code VARCHAR(20) UNIQUE NOT NULL, year_name VARCHAR(100) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_active BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 6. SEMESTERS table (depends on academic_years) const semestersTable = ` CREATE TABLE IF NOT EXISTS semesters ( semester_id INT PRIMARY KEY AUTO_INCREMENT, academic_year_id INT NOT NULL, semester_code VARCHAR(20) UNIQUE NOT NULL, semester_name VARCHAR(50) NOT NULL, semester_type ENUM('semester_i', 'semester_ii', 'summer', 'distance', 'extension', 'weekend') NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_active BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (academic_year_id) REFERENCES academic_years(academic_year_id) ON DELETE CASCADE )`; // 7. PROGRAMS table (depends on departments) const programsTable = ` CREATE TABLE IF NOT EXISTS programs ( program_id INT PRIMARY KEY AUTO_INCREMENT, program_code VARCHAR(20) UNIQUE NOT NULL, program_name VARCHAR(150) NOT NULL, department_id INT NOT NULL, program_type ENUM('regular', 'extension', 'weekend', 'summer', 'distance') NOT NULL, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE )`; // 8. COURSES table (depends on departments and programs) const coursesTable = ` CREATE TABLE IF NOT EXISTS courses ( course_id INT PRIMARY KEY AUTO_INCREMENT, course_code VARCHAR(20) UNIQUE NOT NULL, course_title VARCHAR(200) NOT NULL, department_id INT NOT NULL, program_id INT, academic_year INT, recommended_semester INT, course_order INT DEFAULT 0, credit_hours DECIMAL(4,2) NOT NULL, lecture_hours DECIMAL(4,2) NOT NULL, lab_hours DECIMAL(4,2) DEFAULT 0, tutorial_hours DECIMAL(4,2) DEFAULT 0, program_type ENUM('regular', 'extension', 'weekend', 'summer', 'distance') NOT NULL, course_year INT DEFAULT NULL COMMENT 'Year in curriculum (1-5)', course_semester INT DEFAULT NULL COMMENT 'Semester in curriculum (1 or 2)', is_core_course BOOLEAN DEFAULT TRUE, prerequisites VARCHAR(500), max_students INT DEFAULT 60, min_students INT DEFAULT 15, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE, FOREIGN KEY (program_id) REFERENCES programs(program_id) ON DELETE SET NULL )`; // 9. SECTIONS table (depends on courses, semesters, and staff_profiles) const sectionsTable = ` CREATE TABLE IF NOT EXISTS sections ( section_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, section_code VARCHAR(20) NOT NULL, instructor_id INT, student_count INT DEFAULT 0, max_capacity INT DEFAULT 60, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY unique_section (course_id, semester_id, section_code), FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (instructor_id) REFERENCES staff_profiles(staff_id) ON DELETE SET NULL )`; // 10. WORKLOAD RP table (depends on staff_profiles and semesters) - COMPLETE WITH ALL COLUMNS const workloadRpTable = ` CREATE TABLE IF NOT EXISTS workload_rp ( workload_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, -- Course Details (MANDATORY COLUMNS) course_code VARCHAR(50) NOT NULL, course_credit_hours DECIMAL(5,2) DEFAULT 0, lecture_credit_hours DECIMAL(5,2) DEFAULT 0, tutorial_credit_hours DECIMAL(5,2) DEFAULT 0, lab_credit_hours DECIMAL(5,2) DEFAULT 0, -- Student Details student_department VARCHAR(100), academic_year VARCHAR(50), number_of_sections INT DEFAULT 1, -- Load Calculation each_section_course_load DECIMAL(6,2) DEFAULT 0, variety_of_course_load DECIMAL(6,2) DEFAULT 0, research_load DECIMAL(6,2) DEFAULT 0, community_service_load DECIMAL(6,2) DEFAULT 0, -- Administrative & Other Loads elip_load DECIMAL(6,2) DEFAULT 0, hdp_load DECIMAL(6,2) DEFAULT 0, course_chair_load DECIMAL(6,2) DEFAULT 0, section_advisor_load DECIMAL(6,2) DEFAULT 0, advising_load DECIMAL(6,2) DEFAULT 0, position_load DECIMAL(6,2) DEFAULT 0, -- Summary total_load DECIMAL(6,2) NOT NULL DEFAULT 0, over_payment_birr DECIMAL(10,2) DEFAULT 0, -- Status and Metadata status ENUM( 'draft', 'submitted', 'dh_approved', 'dean_approved', 'hr_approved', 'vpaa_approved', 'vpaf_approved', 'finance_approved', 'rejected' ) DEFAULT 'draft', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, -- Foreign Keys FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, -- Indexes for better performance INDEX idx_staff_id (staff_id), INDEX idx_semester_id (semester_id), INDEX idx_status (status), INDEX idx_course_code (course_code) )`; // 11. WORKLOAD NRP table (depends on staff_profiles, semesters, and courses) - COMPLETE WITH ALL COLUMNS const workloadNrpTable = ` CREATE TABLE IF NOT EXISTS workload_nrp ( nrp_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, program_type ENUM('extension', 'weekend', 'summer', 'distance') NOT NULL, -- Basic Information contract_number VARCHAR(50), academic_year VARCHAR(50), academic_year_ec VARCHAR(50), contract_type ENUM('teaching', 'tutorial_correction', 'combined') DEFAULT 'teaching', -- Course Information course_id INT, course_code VARCHAR(50), course_title VARCHAR(200), -- Hours and Credit Information credit_hours DECIMAL(5,2) DEFAULT 0, lecture_credit_hours DECIMAL(5,2) DEFAULT 0, lab_credit_hours DECIMAL(5,2) DEFAULT 0, tutorial_credit_hours DECIMAL(5,2) DEFAULT 0, lecture_sections INT DEFAULT 0, lab_sections INT DEFAULT 0, tutorial_sessions INT DEFAULT 0, teaching_hours DECIMAL(6,2) DEFAULT 0, module_hours DECIMAL(6,2) DEFAULT 0, -- Student Information student_count INT DEFAULT 0, student_count_dept INT DEFAULT 0, student_count_year INT DEFAULT 0, student_count_section INT DEFAULT 0, assignment_students INT DEFAULT 0, exam_students INT DEFAULT 0, project_advising VARCHAR(255), project_groups INT DEFAULT 0, -- Rate Information rate_category ENUM('A', 'B', 'C', 'default'), rate_per_rank DECIMAL(10,2), assignment_rate DECIMAL(10,2) DEFAULT 25.00, exam_rate DECIMAL(10,2) DEFAULT 20.00, tutorial_rate_per_hour DECIMAL(10,2) DEFAULT 100.00, -- Payment Information teaching_payment DECIMAL(10,2) DEFAULT 0, tutorial_payment DECIMAL(10,2) DEFAULT 0, assignment_payment DECIMAL(10,2) DEFAULT 0, exam_payment DECIMAL(10,2) DEFAULT 0, project_payment DECIMAL(10,2) DEFAULT 0, total_payment DECIMAL(10,2) DEFAULT 0, total_hours_worked DECIMAL(6,2) DEFAULT 0, -- Contract Information contract_duration_from DATE, contract_duration_to DATE, -- Overload Information is_overload BOOLEAN DEFAULT FALSE, overload_hours DECIMAL(6,2) DEFAULT 0, overload_payment DECIMAL(10,2) DEFAULT 0, -- Status and Metadata status ENUM( 'draft', 'submitted', 'dh_approved', 'dean_approved', 'cde_approved', 'hr_approved', 'vpaf_approved', 'finance_approved', 'rejected', 'paid' ) DEFAULT 'draft', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, -- Foreign Keys FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE SET NULL, -- Indexes INDEX idx_nrp_staff_id (staff_id), INDEX idx_nrp_semester_id (semester_id), INDEX idx_nrp_program_type (program_type), INDEX idx_nrp_contract_number (contract_number) )`; // 12. PAYMENT SHEETS table (depends on workload_nrp and users) const paymentSheetsTable = ` CREATE TABLE IF NOT EXISTS payment_sheets ( payment_id INT PRIMARY KEY AUTO_INCREMENT, nrp_id INT, overload_id INT, payment_type ENUM('extension', 'weekend', 'summer', 'distance', 'overload') NOT NULL, sheet_number VARCHAR(50) UNIQUE NOT NULL, gross_amount DECIMAL(12,2) NOT NULL, tax_amount DECIMAL(12,2) DEFAULT 0, net_amount DECIMAL(12,2) NOT NULL, payment_status ENUM('pending', 'approved', 'paid', 'rejected') DEFAULT 'pending', approved_by INT, approved_date DATETIME, export_format ENUM('pdf', 'excel'), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (nrp_id) REFERENCES workload_nrp(nrp_id) ON DELETE SET NULL, FOREIGN KEY (approved_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 13. OVERLOAD PAYMENTS table (depends on staff_profiles and semesters) const overloadPaymentsTable = ` CREATE TABLE IF NOT EXISTS overload_payments ( overload_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, overload_hours DECIMAL(6,2) NOT NULL, rate_used DECIMAL(10,2) NOT NULL, gross_amount DECIMAL(12,2) NOT NULL, tax_amount DECIMAL(12,2) DEFAULT 0, net_amount DECIMAL(12,2) NOT NULL, payment_status ENUM('pending', 'approved', 'paid', 'rejected') DEFAULT 'pending', computed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ruleset_version VARCHAR(20), FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE )`; // 14. TAX RULES table (independent) const taxRulesTable = ` CREATE TABLE IF NOT EXISTS tax_rules ( tax_id INT PRIMARY KEY AUTO_INCREMENT, program_type ENUM('extension', 'weekend', 'summer', 'distance', 'overload') NOT NULL, tax_rate DECIMAL(5,2) NOT NULL, effective_from DATE NOT NULL, effective_to DATE, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 15. RATE TABLES table (independent) const rateTablesTable = ` CREATE TABLE IF NOT EXISTS rate_tables ( rate_id INT PRIMARY KEY AUTO_INCREMENT, program_type ENUM('extension', 'weekend', 'summer', 'distance') NOT NULL, rate_category ENUM('A', 'B', 'C', 'default'), amount_per_credit DECIMAL(10,2), amount_per_hour DECIMAL(10,2), amount_per_student DECIMAL(10,2), effective_from DATE NOT NULL, effective_to DATE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 16. SYSTEM RULES table (independent) const systemRulesTable = ` CREATE TABLE IF NOT EXISTS system_rules ( rule_id INT PRIMARY KEY AUTO_INCREMENT, rule_name VARCHAR(100) NOT NULL, rule_value VARCHAR(255) NOT NULL, rule_type ENUM('load_factor', 'rank_limit', 'payment', 'distribution', 'other') NOT NULL, program_type VARCHAR(50), effective_from DATE NOT NULL, effective_to DATE, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY unique_rule (rule_name, effective_from) )`; // 17. RULESET HISTORY table (depends on users) const rulesetHistoryTable = ` CREATE TABLE IF NOT EXISTS ruleset_history ( history_id INT PRIMARY KEY AUTO_INCREMENT, rule_name VARCHAR(100) NOT NULL, previous_value VARCHAR(255), new_value VARCHAR(255) NOT NULL, changed_by INT, change_reason TEXT, effective_from DATE NOT NULL, effective_to DATE, program_type VARCHAR(50), version_number VARCHAR(20), changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (changed_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 18. SUMMER DISTRIBUTION table (independent) const summerDistributionTable = ` CREATE TABLE IF NOT EXISTS summer_distribution ( dist_id INT PRIMARY KEY AUTO_INCREMENT, stage1_percent DECIMAL(5,2) DEFAULT 30.00, stage2_percent DECIMAL(5,2) DEFAULT 30.00, stage3_percent DECIMAL(5,2) DEFAULT 20.00, stage4_percent DECIMAL(5,2) DEFAULT 20.00, effective_from DATE NOT NULL, effective_to DATE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 19. APPROVAL WORKFLOW table (depends on users) const approvalWorkflowTable = ` CREATE TABLE IF NOT EXISTS approval_workflow ( approval_id INT PRIMARY KEY AUTO_INCREMENT, entity_type ENUM('workload_rp', 'workload_nrp', 'overload') NOT NULL, entity_id INT NOT NULL, approver_role VARCHAR(50) NOT NULL, approver_id INT, status ENUM('pending', 'approved', 'rejected', 'returned') DEFAULT 'pending', comments TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_entity (entity_type, entity_id), INDEX idx_approver (approver_role, status), FOREIGN KEY (approver_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 20. AUDIT LOG table (depends on users) const auditLogTable = ` CREATE TABLE IF NOT EXISTS audit_log ( audit_id INT PRIMARY KEY AUTO_INCREMENT, user_id INT NOT NULL, action VARCHAR(100) NOT NULL, entity VARCHAR(50) NOT NULL, entity_id INT, old_value TEXT, new_value TEXT, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ip_address VARCHAR(45), FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE )`; // 21. WORKLOAD DETAIL RP table (depends on workload_rp) const workloadDetailRpTable = ` CREATE TABLE IF NOT EXISTS workload_detail_rp ( detail_id INT PRIMARY KEY AUTO_INCREMENT, workload_id INT NOT NULL, detail_type ENUM('research', 'community', 'note') NOT NULL, description TEXT, hours DECIMAL(6,2) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (workload_id) REFERENCES workload_rp(workload_id) ON DELETE CASCADE )`; // 22. NRP CONTRACT TEMPLATES table (depends on users) const nrpContractTemplatesTable = ` CREATE TABLE IF NOT EXISTS nrp_contract_templates ( template_id INT PRIMARY KEY AUTO_INCREMENT, template_name VARCHAR(100) NOT NULL, template_type VARCHAR(50), program_type VARCHAR(50), header_content TEXT, stipulation_content TEXT, table_structure JSON, signature_fields JSON, created_by INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 23. NRP REPORTS table (depends on semesters, departments, colleges, users) const nrpReportsTable = ` CREATE TABLE IF NOT EXISTS nrp_reports ( report_id INT PRIMARY KEY AUTO_INCREMENT, report_type VARCHAR(50) NOT NULL, semester_id INT, department_id INT, college_id INT, report_period VARCHAR(100), generated_by INT NOT NULL, report_data JSON, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE SET NULL, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE SET NULL, FOREIGN KEY (college_id) REFERENCES colleges(college_id) ON DELETE SET NULL, FOREIGN KEY (generated_by) REFERENCES users(user_id) ON DELETE CASCADE )`; // 24. COURSE ASSIGNMENTS table (depends on courses, semesters, staff_profiles, users) const courseAssignmentsTable = ` CREATE TABLE IF NOT EXISTS course_assignments ( assignment_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, staff_id INT NOT NULL, student_year INT, assigned_by INT NOT NULL, section_code VARCHAR(20), assigned_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP, status ENUM('assigned', 'accepted', 'declined', 'withdrawn') DEFAULT 'assigned', notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY unique_course_assignment (course_id, semester_id, staff_id), FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (assigned_by) REFERENCES users(user_id) ON DELETE CASCADE )`; // 25. COURSE REQUESTS table (depends on courses, semesters, staff_profiles, users) const courseRequestsTable = ` CREATE TABLE IF NOT EXISTS course_requests ( request_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, staff_id INT NOT NULL, requested_by INT NOT NULL, section_code VARCHAR(20), preferred_schedule VARCHAR(100), reason TEXT, status ENUM('pending', 'approved', 'rejected', 'cancelled') DEFAULT 'pending', processed_by INT, processed_date DATETIME, processed_notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (requested_by) REFERENCES users(user_id) ON DELETE CASCADE, FOREIGN KEY (processed_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 26. CURRICULUM PLANS table (depends on departments, programs, courses) const curriculumPlansTable = ` CREATE TABLE IF NOT EXISTS curriculum_plans ( plan_id INT PRIMARY KEY AUTO_INCREMENT, department_id INT NOT NULL, program_id INT