y(tableName, processedRecord) // ); // // Store the generated ID for future relationships // if (result.insertId) { // idMaps[tableName][ // record || record.original_id || result.insertId // ] = result.insertId; // } // console.log(` ✓ Inserted ${tableName} record`); // } catch (error) { // console.error( // ` ✗ Failed to insert ${tableName} record:`, // error.message // ); // throw error; // } // } // } // } // console.log( // "✅ Exact data inserted successfully with proper relationships!" // ); // } catch (error) { // console.error("❌ Failed to insert exact data:", error.message); // throw error; // } // }; // ============================================ // EXACT DATA INSERTION FUNCTION - WITHOUT TEMP_ID // ============================================ export const insertExactData = async (exactData = {}) => { console.log("📝 Inserting exact data with proper relationships..."); try { if (!exactData || Object.keys(exactData).length === 0) { console.log("⚠️ No data provided. Using minimal required data..."); return; } // Create mappings to track IDs for relationships const idMaps = { users: {}, colleges: {}, departments: {}, staff_profiles: {}, academic_years: {}, semesters: {}, programs: {}, courses: {}, sections: {}, workload_rp: {}, workload_nrp: {} }; // Insert users first (no dependencies) if (exactData.users && exactData.users.length > 0) { console.log(`📋 Inserting ${exactData.users.length} users...`); for (const record of exactData.users) { try { const processedRecord = { ...record }; // Remove fields that don't exist in the table delete processedRecord.created_by_username; // Build SQL query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => { const value = processedRecord[key]; if (typeof value === 'boolean') return value ? 1 : 0; if (value instanceof Date) return value.toISOString().split('T')[0]; return value; }); const sql = `INSERT INTO users (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by username if (result.insertId && record.username) { idMaps.users[record.username] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert user:`, error.message); console.error(` Record:`, record); throw error; } } } // Insert colleges (depends on users for dean_user_id) if (exactData.colleges && exactData.colleges.length > 0) { console.log(`📋 Inserting ${exactData.colleges.length} colleges...`); for (const record of exactData.colleges) { try { const processedRecord = { ...record }; // Handle dean_user_id relationship if (record.dean_username && idMaps.users[record.dean_username]) { processedRecord.dean_user_id = idMaps.users[record.dean_username]; } delete processedRecord.dean_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO colleges (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by college_code if (result.insertId && record.college_code) { idMaps.colleges[record.college_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert college:`, error.message); throw error; } } } // Insert departments (depends on colleges and users) if (exactData.departments && exactData.departments.length > 0) { console.log(`📋 Inserting ${exactData.departments.length} departments...`); for (const record of exactData.departments) { try { const processedRecord = { ...record }; // Handle relationships if (record.college_code && idMaps.colleges[record.college_code]) { processedRecord.college_id = idMaps.colleges[record.college_code]; } if (record.head_username && idMaps.users[record.head_username]) { processedRecord.head_user_id = idMaps.users[record.head_username]; } delete processedRecord.college_code; delete processedRecord.head_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO departments (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by department_code if (result.insertId && record.department_code) { idMaps.departments[record.department_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert department:`, error.message); throw error; } } } // Insert staff_profiles (depends on users and departments) if (exactData.staff_profiles && exactData.staff_profiles.length > 0) { console.log(`📋 Inserting ${exactData.staff_profiles.length} staff profiles...`); for (const record of exactData.staff_profiles) { try { const processedRecord = { ...record }; // Handle relationships if (record.username && idMaps.users[record.username]) { processedRecord.user_id = idMaps.users[record.username]; } if (record.department_code && idMaps.departments[record.department_code]) { processedRecord.department_id = idMaps.departments[record.department_code]; } if (record.created_by_username && idMaps.users[record.created_by_username]) { processedRecord.created_by = idMaps.users[record.created_by_username]; } delete processedRecord.username; delete processedRecord.department_code; delete processedRecord.created_by_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO staff_profiles (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by employee_id (assuming it's unique) if (result.insertId && record.employee_id) { idMaps.staff_profiles[record.employee_id] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert staff profile:`, error.message); throw error; } } } // Insert academic_years (no dependencies) if (exactData.academic_years && exactData.academic_years.length > 0) { console.log(`📋 Inserting ${exactData.academic_years.length} academic years...`); for (const record of exactData.academic_years) { try { // Build and execute query const columns = Object.keys(record).filter(key => record[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => record[key]); const sql = `INSERT INTO academic_years (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by year_code if (result.insertId && record.year_code) { idMaps.academic_years[record.year_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert academic year:`, error.message); throw error; } } } // Continue with other tables in dependency order... // Follow the same pattern for semesters, programs, courses, etc. console.log("✅ Exact data inserted successfully!"); return idMaps; // Return the ID mappings for debugging } catch (error) { console.error("❌ Failed to insert exact data:", error.message); throw error; } }; // Helper function to build INSERT query const buildInsertQuery = (tableName, record) => { const columns = Object.keys(record).join(", "); const placeholders = Object.keys(record) .map(() => "?") .join(", "); const values = Object.values(record); return `INSERT INTO ${tableName} (${columns}) VALUES (${placeholders})`; }; // Helper function to process relationships between tables const processRelationships = async (tableName, record, idMaps) => { const processedRecord = { ...record }; switch (tableName) { case "departments": if (record.college_code && idMaps.colleges[record.